import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;

public class PasswordSecurity {
    private static final BCryptPasswordEncoder encoder = new BCryptPasswordEncoder();

    // SECURE - Hashing passwords with bcrypt
    public static String hashPassword(String plainPassword) {
        // BCrypt automatically generates salt
        return encoder.encode(plainPassword);
    }

    // SECURE - Verifying passwords against hash
    public static boolean verifyPassword(String plainPassword, String hashedPassword) {
        return encoder.matches(plainPassword, hashedPassword);
    }

    // VULNERABLE - Never store passwords this way!
    public static String insecureHash(String password) {
        // Using MD5 without salt - easily crackable
        try {
            MessageDigest md = MessageDigest.getInstance("MD5");
            byte[] hash = md.digest(password.getBytes());
            return bytesToHex(hash);  // NOT SECURE!
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }
}

#include <stdio.h>
#include <string.h>
#include <stdlib.h>

// VULNERABLE - No bounds checking
void unsafe_copy(char *dest, char *source) {
    strcpy(dest, source);  // Can overflow if source > dest
}

// SECURE - With bounds checking
void safe_copy(char *dest, size_t dest_size, const char *source) {
    // Use strncpy with null termination guarantee
    strncpy(dest, source, dest_size - 1);
    dest[dest_size - 1] = '\0';  // Ensure null termination
}

// SECURE - Using snprintf
void safer_copy(char *dest, size_t dest_size, const char *source) {
    snprintf(dest, dest_size, "%s", source);
}

// SECURE - Dynamic allocation with checking
char* safest_copy(const char *source) {
    size_t len = strlen(source);
    char *dest = malloc(len + 1);  // Allocate exact size needed
    if (dest != NULL) {
        strcpy(dest, source);
    }
    return dest;
}

// VULNERABLE - Direct HTML insertion
function vulnerableDisplay(userInput) {
    document.getElementById('output').innerHTML = userInput;  // XSS POSSIBLE!
}

// SECURE - HTML Encoding
function secureDisplay(userInput) {
    // Encode special characters to HTML entities
    const encoded = encodeHTML(userInput);
    document.getElementById('output').textContent = encoded;
}

// HTML Entity Encoding Function
function encodeHTML(str) {
    const map = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#x27;',
        '/': '&#x2F;'
    };
    return str.replace(/[&<>"'/]/g, char => map[char]);
}

// SECURE - Using DOM textContent
function safestDisplay(userInput) {
    // textContent automatically escapes HTML
    document.getElementById('output').textContent = userInput;
}

